#include <bits/stdc++.h>
using namespace std;

const int N=1e6+6,mod=1e9+7;

int n,q,s[2][N],f[2][N],mi[N];
char str[N];

int main(){
    scanf("%d%d",&n,&q);
    scanf("%s",str+1);
    mi[0]=1;
    for(int i=1;i<=n;i++){
    	s[0][i]=s[0][i-1],s[1][i]=s[1][i-1];
    	s[str[i]-'0'][i]++;
    	f[0][i]=(f[0][i-1]*2+str[i]-'0')%mod;
		f[1][i]=(f[1][i-1]*2+1-(str[i]-'0'))%mod;
		mi[i]=mi[i-1]*2%mod;
	}
	while(q--){
		int l,r,k;
		scanf("%d%d%d",&l,&r,&k);
		if(s[0][r]-s[0][l-1]>=k && s[1][r]-s[1][l-1]>=k){
			printf("%d\n",mi[k]-1);
			continue;
		}
		if(s[0][r]-s[0][l-1]<k){
			int left=l,right=r;
			while(left<right){
				int mid=left+right>>1;
				if(s[0][r]-s[0][l-1]+s[1][r]-s[1][mid-1]<=k)
					right=mid;
				else
					left=mid+1;
			}
			int p=left;
			printf("%d\n",((f[1][r]-1LL*f[1][p-1]*mi[r-p+1]%mod+mod)%mod+1LL*(mi[k-(r-p+1)]-1)*mi[r-p+1]%mod)%mod);
		}else{
			int left=l,right=r;
			while(left<right){
				int mid=left+right>>1;
				if(s[1][r]-s[1][l-1]+s[0][r]-s[0][mid-1]<=k)
					right=mid;
				else
					left=mid+1;
			}
			int p=left;
			printf("%d\n",((f[0][r]-1LL*f[0][p-1]*mi[r-p+1]%mod+mod)%mod+1LL*(mi[k-(r-p+1)]-1)*mi[r-p+1]%mod)%mod);
		}
	}
    return 0;
}
